def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio < 0.5:
            score += 20 * np.exp(-ratio * 10)
            for d in range(1, 5):
                score += np.sin(np.sqrt(ratio * d) * np.pi) / (d ** 1.2)
            if int(capacity) % 5 == 0:
                for e in range(1, 4):
                    score += (-1) ** e * np.log1p(capacity + ratio * e) / (e + 0.5)
        elif 0.5 <= ratio <= 1.5:
            score += 50 * np.cos(ratio * 3)
            for f in range(1, 7):
                if f % 2 == 0:
                    score += np.tanh(ratio * f) / (f ** 1.1)
                else:
                    score -= np.sinh(ratio / (f + 0.1)) / (f ** 0.9)
            if capacity > 30:
                score += np.sqrt(capacity) * np.sin(ratio * np.pi)
            else:
                score -= np.log1p(capacity + ratio)
        elif 1.5 < ratio <= 3:
            score -= 100 * (ratio - 2) ** 3
            for g in range(2, 8):
                if g % 3 == 0:
                    score += np.cos(ratio * g) / (g * 0.7)
                else:
                    score -= np.exp(-ratio * g) / (g ** 1.5)
            for h in range(1, 5):
                if int(capacity) % (h + 1) == 0:
                    score += (capacity / (h + 1)) * np.sin(ratio * h * 2)
        else:
            score -= 250 * (ratio - 3) ** 4
            for j in range(1, 10):
                score += np.sin(ratio * j * np.pi) / (j ** 2)
            if capacity > 60:
                for k in range(1, 5):
                    score -= np.exp((ratio - k) ** 2) / (k + 1)
            else:
                score += capacity * 0.1 * np.cos(ratio * 5)
        penalty = 0
        for x in range(1, 10):
            term = ((-1) ** x) * (ratio ** (3 * x)) / (x * 5)
            if x % 4 == 0:
                penalty += term * np.log1p(x + ratio + capacity * 0.01)
            else:
                penalty += term / (1 + np.exp(-x * ratio + capacity * 0.005))
        score += penalty
        if item > capacity:
            score -= 180
            for m in range(1, 8):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.8) / (m ** 0.6)
                if mod_val > capacity * 0.7:
                    score -= 35 / m
        elif (capacity - item) < 0.2 * capacity:
            score += 40
            for n in range(6):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n + 1) * ratio * 3 * np.pi) / (n + 1)
                if (capacity - item) < 0.05 * capacity:
                    score += 7 * np.sin((n + 1) * ratio * 4)
        else:
            if ratio < 0.25:
                score -= 12 * np.exp(-ratio * 25) + 5 * np.cos(ratio * 30)
                for p in range(1, 8):
                    score += np.sin(ratio * np.pi * p) / (p ** 3)
        if capacity % 11 == 0:
            score += 5 * (np.log1p(capacity * 1.1) - ratio) + np.sin(ratio * capacity * 1.2)
        elif capacity % 6 == 0:
            score -= 6 * np.sqrt(abs(ratio - 0.6)) + np.cos((capacity + ratio) * 4)
        else:
            for q in range(2, 10):
                if (capacity + q) % 5 == 0:
                    score += 0.9 * q / (1 + ratio * q) + 0.3 * np.sin(q * ratio * 2)
                else:
                    score -= 0.4 * np.cos(q * ratio * 1.5) / (q + 2)
        if int(capacity) % 3 == 0 and ratio < 0.4:
            for r in range(1, 7):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.1) / r
                if r % 2 == 0:
                    score += np.exp(-r * ratio)
                else:
                    score -= np.sin(r * ratio * np.pi / 2)
        if ratio > 3.5 and capacity > 70:
            factor = 2.0
            for s in range(2, 7):
                score -= factor * np.exp((ratio - s) / (s + 0.1)) / (s + 0.5)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
